goal = "Analyze market trends for AI startup pricing"
subtasks = [
    {"task": "scrape", "domain": "web_scraper", "query": "AI startup pricing 2026"},
    {"task": "analyze", "domain": "data_analyst", "data": "scraped_results"},
    {"task": "write", "domain": "writer", "summary": "analysis_results"}
]

for task in subtasks:
    subagent = get_subagent_by_domain(task["domain"])
    subagent.invoke({
        "task": task["task"],
        "query": task["query"],
        "goal": goal
    })

results = {}
for task in subtasks:
    subagent = get_subagent_by_domain(task["domain"])
    results[task["task"]] = subagent.invoke({
        "task": task["task"],
        "query": task["query"]
    })

def execute_with_retry(task, max_retries=3):
    for i in range(max_retries):
        try:
            subagent = get_subagent_by_domain(task["domain"])
            return subagent.invoke(task)
        except Exception as e:
            if i == max_retries - 1:
                raise e
            # Retry or re-route

# Orchestrator
for task in subtasks:
    celery_app.send_task(
        "run_subagent",
        args=[task["domain"], task],
        queue=f"domain_{task['domain']}"
    )

# Subagent worker
@celery_app.task(name="run_subagent")
def run_subagent(domain: str, task: dict):
    subagent = get_subagent_by_domain(domain)
    return subagent.invoke(task)
